section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/devops-lb-ssl-tls.json",
  "title": "SSL/TLS Termination at the Load Balancer",
  "type": "object",
  "required": [
    "strategy",
    "min_tls_version",
    "cipher_list",
    "hsts",
    "ocsp_stapling",
    "cert_source",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "strategy": {
      "enum": [
        "termination",
        "re_encryption",
        "passthrough"
      ]
    },
    "min_tls_version": {
      "enum": [
        "TLSv1.2",
        "TLSv1.3"
      ]
    },
    "cipher_list": {
      "type": "array",
      "minItems": 3
    },
    "hsts": {
      "type": "object",
      "required": [
        "enabled",
        "max_age",
        "include_subdomains",
        "preload"
      ]
    },
    "ocsp_stapling": {
      "type": "boolean"
    },
    "cert_source": {
      "enum": [
        "cert_manager",
        "acm",
        "letsencrypt",
        "manual"
      ]
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
